local a={}if module then mbox=a end;function a.split_message(b)local c={}b=string.gsub(b,"\r\n","\n")string.gsub(b,"^(.-\n)\n",function(d)c.headers=d end)string.gsub(b,"^.-\n\n(.*)",function(e)c.body=e end)if not c.body then string.gsub(b,"^\n(.*)",function(e)c.body=e end)end;if not c.headers and not c.body then c.headers=b end;return c.headers or"",c.body or""end;function a.split_headers(f)local g={}f=string.gsub(f,"\r\n","\n")f=string.gsub(f,"\n[ ]+"," ")string.gsub("\n"..f,"\n([^\n]+)",function(d)table.insert(g,d)end)return g end;function a.parse_header(h)h=string.gsub(h,"\n[ ]+"," ")h=string.gsub(h,"\n+","")local i,j,k,l=string.find(h,"([^%s:]-):%s*(.*)")return k,l end;function a.parse_headers(f)local m=a.split_headers(f)local g={}for n=1,#m do local k,l=a.parse_header(m[n])if k then k=string.lower(k)if g[k]then g[k]=g[k]..", "..l else g[k]=l end end end;return g end;function a.parse_from(o)local i,j,k,p=string.find(o,"^%s*(.-)%s*%<(.-)%>")if not p then i,j,p=string.find(o,"%s*(.+)%s*")end;k=k or""p=p or""if k==""then k=p end;k=string.gsub(k,'"',"")return k,p end;function a.split_mbox(q)local mbox={}q=string.gsub(q,"\r\n","\n").."\n\nFrom \n"local r,n,s=1,1,1;while 1 do n,r=string.find(q,"\n\nFrom .-\n",s)if not n then break end;local c=string.sub(q,s,n-1)table.insert(mbox,c)s=r+1 end;return mbox end;function a.parse(q)local mbox=a.split_mbox(q)for n=1,#mbox do mbox[n]=a.parse_message(mbox[n])end;return mbox end;function a.parse_message(b)local c={}c.headers,c.body=a.split_message(b)c.headers=a.parse_headers(c.headers)return c end;return a